/**
 * Haptic Feedback Utility with iOS Audio-Tactile support
 * Uses the Web Vibration API for Android and a micro-click audio trick for iOS.
 */

// Premium 'Liquid Glass' UI Pop - Soft, modern, and high-end
const CLICK_SOUND_DATA = "data:audio/wav;base64,";

let clickAudio = null;
let notifyAudio = null;

if (typeof window !== 'undefined') {
  clickAudio = new Audio(CLICK_SOUND_DATA);
  clickAudio.volume = 0.15; // Refined low volume for subtle 'luxurious' feel
  clickAudio.preload = 'auto'; // Force buffer for zero-latency

  // NOTIFY_SOUND_DATA: Melodic 'Rebound' style
  const NOTIFY_SOUND_DATA = "data:audio/wav;base64,";
  notifyAudio = new Audio(NOTIFY_SOUND_DATA);
  notifyAudio.volume = 0.35;
  notifyAudio.preload = 'auto';
}

const playClick = () => {
  if (clickAudio) {
    const sound = clickAudio.cloneNode();
    sound.volume = 0.15;
    sound.play().catch(() => {});
  }
};

const playNotify = () => {
  if (notifyAudio) {
    const sound = notifyAudio.cloneNode();
    sound.volume = 0.35;
    sound.play().catch(() => {});
  }
};

export const haptics = {
  // Light tap
  light: () => {
    playClick();
    if (typeof window !== 'undefined' && window.navigator.vibrate) {
      window.navigator.vibrate(40);
    }
  },

  // Ultra-soft tap (Perfect for iOS PWA navigation)
  soft: () => {
    if (clickAudio) {
      const sound = clickAudio.cloneNode();
      sound.volume = 0.08;
      sound.play().catch(() => {});
    }
    if (typeof window !== 'undefined' && window.navigator.vibrate) {
      window.navigator.vibrate(20);
    }
  },
  
  // Standard / Medium tap
  medium: () => {
    playClick();
    if (typeof window !== 'undefined' && window.navigator.vibrate) {
      window.navigator.vibrate(70);
    }
  },
  
  // Success pattern
  success: () => {
    playNotify(); 
    if (typeof window !== 'undefined' && window.navigator.vibrate) {
      window.navigator.vibrate([60, 100, 60]);
    }
  },
  
  // Error / Warning pattern
  error: () => {
    playClick();
    setTimeout(playClick, 150);
    setTimeout(playClick, 300); // Triple click for iOS
    if (typeof window !== 'undefined' && window.navigator.vibrate) {
      window.navigator.vibrate([150, 80, 150, 80, 200]);
    }
  },

  // Premium Melodic Notification (re-bounce)
  notify: () => {
    playNotify();
    if (typeof window !== 'undefined' && window.navigator.vibrate) {
      window.navigator.vibrate([30, 200, 30]);
    }
  }
};

